SELECT

FROM M_STOCK_PRICE_HISTORY

    STOCK_CODE = #{stockCode}

        AND TRANS_DATE >= #{dateFrom}


        AND TRANS_DATE <= #{dateTo}


ORDER BY

        ID
        TRANS_DATE


        ASC
        DESC

LIMIT #{limit} OFFSET #{offset}

SELECT
    COUNT(1)
FROM M_STOCK_PRICE_HISTORY

    STOCK_CODE = #{stockCode}

        AND TRANS_DATE >= #{dateFrom}


        AND TRANS_DATE <= #{dateTo}

SELECT

FROM M_STOCK_PRICE_HISTORY
WHERE STOCK_CODE = #{stockCode}
  AND TRANS_DATE = #{transDate}
